package com.example.sso.controller;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;

import java.io.IOException;
import java.net.URI;
import java.net.URISyntaxException;
import java.util.List;

@Controller
public class LogoutController {

    @Value("${sso.allowed-redirect-domains}")
    private List<String> allowedRedirectDomains;

    @Value("${sso.default-redirect-url}")
    private String defaultRedirectUrl;

    @GetMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        // Invalidate the session
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }

        // Clear any authentication cookies
        jakarta.servlet.http.Cookie[] cookies = request.getCookies();
        if (cookies != null) {
            for (jakarta.servlet.http.Cookie cookie : cookies) {
                if ("JSESSIONID".equals(cookie.getName()) || "SSO_TOKEN".equals(cookie.getName())) {
                    cookie.setValue("");
                    cookie.setPath("/");
                    cookie.setMaxAge(0);
                    cookie.setHttpOnly(true);
                    cookie.setSecure(true);
                    response.addCookie(cookie);
                }
            }
        }

        // Validate and sanitize the redirect URL
        String nextUrl = request.getParameter("next");
        String safeRedirectUrl = validateRedirectUrl(nextUrl);

        response.sendRedirect(safeRedirectUrl);
    }

    private String validateRedirectUrl(String url) {
        if (url == null || url.isBlank()) {
            return defaultRedirectUrl;
        }

        // Trim whitespace
        url = url.trim();

        // Block URLs with dangerous schemes or encoded characters that could lead to open redirect
        // Reject URLs starting with // (protocol-relative), javascript:, data:, etc.
        String lowerUrl = url.toLowerCase();
        if (lowerUrl.startsWith("javascript:") ||
                lowerUrl.startsWith("data:") ||
                lowerUrl.startsWith("vbscript:") ||
                lowerUrl.startsWith("//") ||
                lowerUrl.contains("\r") ||
                lowerUrl.contains("\n") ||
                lowerUrl.contains("%0d") ||
                lowerUrl.contains("%0a")) {
            return defaultRedirectUrl;
        }

        // Only allow http and https schemes
        if (!lowerUrl.startsWith("http://") && !lowerUrl.startsWith("https://")) {
            return defaultRedirectUrl;
        }

        try {
            URI uri = new URI(url);

            // Ensure the URI is absolute and has a valid host
            String host = uri.getHost();
            if (host == null || host.isBlank()) {
                return defaultRedirectUrl;
            }

            // Reject if userinfo is present (e.g., http://evil.com@trusted.com)
            if (uri.getUserInfo() != null) {
                return defaultRedirectUrl;
            }

            // Check against the allowlist of domains
            if (isAllowedDomain(host)) {
                // Reconstruct the URL to normalize it and prevent any tricks
                URI sanitizedUri = new URI(
                        uri.getScheme(),
                        null, // no userinfo
                        uri.getHost(),
                        uri.getPort(),
                        uri.getPath(),
                        uri.getQuery(),
                        uri.getFragment()
                );
                return sanitizedUri.toASCIIString();
            }

        } catch (URISyntaxException e) {
            // Invalid URL, fall through to default
        }

        return defaultRedirectUrl;
    }

    private boolean isAllowedDomain(String host) {
        if (host == null || allowedRedirectDomains == null) {
            return false;
        }

        String normalizedHost = host.toLowerCase();

        for (String allowedDomain : allowedRedirectDomains) {
            String normalizedAllowed = allowedDomain.toLowerCase().trim();

            // Exact match
            if (normalizedHost.equals(normalizedAllowed)) {
                return true;
            }

            // Subdomain match: host ends with ".allowedDomain"
            if (normalizedHost.endsWith("." + normalizedAllowed)) {
                return true;
            }
        }

        return false;
    }
}